"use client";

import * as React from "react";
import { ListMusicIcon } from "lucide-react";

import { useAudioPlayer } from "@/components/ui/audio-player";
import { EqualizerBars } from "@/components/ui/track-list";
import { cn } from "@/lib/utils";

/**
 * Up Next — the Apple Music queue: the current track pinned on
 * top, upcoming tracks below; tap a row to jump to it.
 */
function QueueList({
  className,
  title = "Playing Next",
  ...props
}: React.ComponentProps<"div"> & { title?: string }) {
  const { queue, index, playing, play } = useAudioPlayer();
  const upcoming = queue.slice(index + 1);

  return (
    <div
      data-slot="queue-list"
      className={cn("flex h-full flex-col gap-2 overflow-y-auto px-5", className)}
      {...props}
    >
      <div className="flex items-center justify-between pb-1">
        <h3 className="text-headline">{title}</h3>
        <ListMusicIcon className="size-4 text-secondary-label" />
      </div>

      {queue[index] ? (
        <Row
          artworkUrl={queue[index].artworkUrl}
          title={queue[index].title}
          artist={queue[index].artist}
          trailing={<EqualizerBars paused={!playing} />}
        />
      ) : null}

      {upcoming.length > 0 ? (
        <div className="flex flex-col [&>button:not(:first-child)]:shadow-[0_-0.5px_0_0_var(--separator)]">
          {upcoming.map((t, i) => (
            <Row
              key={t.id}
              asButton
              artworkUrl={t.artworkUrl}
              title={t.title}
              artist={t.artist}
              onSelect={() => play(queue, index + 1 + i)}
            />
          ))}
        </div>
      ) : (
        <p className="py-6 text-center text-footnote text-secondary-label">
          Nothing playing next.
        </p>
      )}
    </div>
  );
}

function Row({
  artworkUrl,
  title,
  artist,
  trailing,
  asButton,
  onSelect,
}: {
  artworkUrl?: string;
  title: string;
  artist: string;
  trailing?: React.ReactNode;
  asButton?: boolean;
  onSelect?: () => void;
}) {
  const Comp: React.ElementType = asButton ? "button" : "div";

  return (
    <Comp
      type={asButton ? "button" : undefined}
      onClick={onSelect}
      className={cn(
        "flex w-full items-center gap-3 py-2 text-left outline-none",
        asButton &&
          "cursor-default select-none focus-visible:bg-fill-quaternary active:bg-fill-tertiary"
      )}
    >
      {artworkUrl ? (
        // eslint-disable-next-line @next/next/no-img-element
        <img
          src={artworkUrl}
          alt=""
          loading="lazy"
          className="size-11 shrink-0 rounded-[6px] object-cover shadow-[inset_0_0_0_0.5px_var(--separator)]"
        />
      ) : (
        <span className="size-11 shrink-0 rounded-[6px] bg-fill-tertiary" />
      )}
      <span className="flex min-w-0 flex-1 flex-col">
        <span className="truncate text-subheadline text-label">{title}</span>
        <span className="truncate text-footnote text-secondary-label">
          {artist}
        </span>
      </span>
      {trailing}
    </Comp>
  );
}

export { QueueList };

"use client";

import * as React from "react";

/**
 * Audio engine for the music components. Wraps one HTMLAudioElement
 * in a context: queue, transport, seeking, and volume — the model
 * behind MusicKit's player, sized for the web.
 */
type AudioTrack = {
  id: string;
  title: string;
  artist: string;
  album?: string;
  /** Square artwork URL. */
  artworkUrl?: string;
  /** Playable audio URL (mp3/m4a). */
  audioUrl: string;
  /** Known duration in seconds, shown before metadata loads. */
  duration?: number;
};

type AudioPlayerState = {
  queue: AudioTrack[];
  index: number;
  track: AudioTrack | null;
  playing: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  /** Replace the queue and start playing at startIndex. */
  play: (queue?: AudioTrack[], startIndex?: number) => void;
  /** Replace the queue WITHOUT starting playback (no autoplay). */
  load: (queue: AudioTrack[], startIndex?: number) => void;
  toggle: () => void;
  next: () => void;
  prev: () => void;
  seek: (seconds: number) => void;
  setVolume: (volume: number) => void;
};

const AudioPlayerContext = React.createContext<AudioPlayerState | null>(null);

function useAudioPlayer() {
  const ctx = React.useContext(AudioPlayerContext);
  if (!ctx)
    throw new Error("useAudioPlayer must be used inside <AudioPlayerProvider>");
  return ctx;
}

function AudioPlayerProvider({ children }: { children: React.ReactNode }) {
  const audioRef = React.useRef<HTMLAudioElement | null>(null);
  const [queue, setQueue] = React.useState<AudioTrack[]>([]);
  const [index, setIndex] = React.useState(-1);
  const [playing, setPlaying] = React.useState(false);
  const [currentTime, setCurrentTime] = React.useState(0);
  const [duration, setDuration] = React.useState(0);
  const [volume, setVolumeState] = React.useState(0.8);

  const track = index >= 0 ? (queue[index] ?? null) : null;

  const audio = React.useCallback(() => {
    if (!audioRef.current && typeof window !== "undefined") {
      audioRef.current = new Audio();
      audioRef.current.preload = "metadata";
    }
    return audioRef.current;
  }, []);

  // Load + play whenever the current track changes.
  React.useEffect(() => {
    const el = audio();
    if (!el || !track) return;
    el.src = track.audioUrl;
    el.volume = volume;
    setCurrentTime(0);
    setDuration(track.duration ?? 0);
    if (playing) void el.play().catch(() => setPlaying(false));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [track?.id]);

  React.useEffect(() => {
    const el = audio();
    if (!el) return;
    if (playing) void el.play().catch(() => setPlaying(false));
    else el.pause();
  }, [playing, audio]);

  React.useEffect(() => {
    const el = audio();
    if (!el) return;
    const onTime = () => setCurrentTime(el.currentTime);
    const onMeta = () => setDuration(el.duration || 0);
    const onEnded = () =>
      setIndex((i) => {
        if (i + 1 < queue.length) return i + 1;
        setPlaying(false);
        return i;
      });
    el.addEventListener("timeupdate", onTime);
    el.addEventListener("loadedmetadata", onMeta);
    el.addEventListener("ended", onEnded);
    return () => {
      el.removeEventListener("timeupdate", onTime);
      el.removeEventListener("loadedmetadata", onMeta);
      el.removeEventListener("ended", onEnded);
    };
  }, [audio, queue.length]);

  // Release the element on unmount.
  React.useEffect(
    () => () => {
      audioRef.current?.pause();
      audioRef.current = null;
    },
    []
  );

  const play = React.useCallback(
    (nextQueue?: AudioTrack[], startIndex = 0) => {
      if (nextQueue) {
        setQueue(nextQueue);
        setIndex(startIndex);
      } else if (index < 0 && queue.length > 0) {
        setIndex(0);
      }
      setPlaying(true);
    },
    [index, queue.length]
  );

  const load = React.useCallback((nextQueue: AudioTrack[], startIndex = 0) => {
    setPlaying(false);
    setQueue(nextQueue);
    setIndex(startIndex);
  }, []);

  const toggle = React.useCallback(() => setPlaying((p) => !p), []);

  const next = React.useCallback(
    () => setIndex((i) => Math.min(i + 1, queue.length - 1)),
    [queue.length]
  );

  const prev = React.useCallback(() => {
    const el = audio();
    // Like iOS: restart the track unless we're within the first 3 s.
    if (el && el.currentTime > 3) {
      el.currentTime = 0;
      setCurrentTime(0);
      return;
    }
    setIndex((i) => Math.max(0, i - 1));
  }, [audio]);

  const seek = React.useCallback(
    (seconds: number) => {
      const el = audio();
      if (!el) return;
      el.currentTime = seconds;
      setCurrentTime(seconds);
    },
    [audio]
  );

  const setVolume = React.useCallback(
    (v: number) => {
      const el = audio();
      if (el) el.volume = v;
      setVolumeState(v);
    },
    [audio]
  );

  return (
    <AudioPlayerContext.Provider
      value={{
        queue,
        index,
        track,
        playing,
        currentTime,
        duration,
        volume,
        play,
        load,
        toggle,
        next,
        prev,
        seek,
        setVolume,
      }}
    >
      {children}
    </AudioPlayerContext.Provider>
  );
}

/** 92 → "1:32" */
function formatTime(seconds: number) {
  if (!Number.isFinite(seconds) || seconds < 0) return "0:00";
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${String(s).padStart(2, "0")}`;
}

export {
  AudioPlayerProvider,
  formatTime,
  useAudioPlayer,
  type AudioTrack,
};

"use client";

import * as React from "react";
import { EllipsisIcon } from "lucide-react";

import { cn } from "@/lib/utils";

/**
 * The Apple Music track list: numbered rows with hairline
 * separators; the current track swaps its number for animated
 * equalizer bars.
 */
function EqualizerBars({ paused }: { paused?: boolean }) {
  return (
    <span
      aria-hidden
      className="flex h-3.5 items-end gap-[2px] text-red"
      data-slot="equalizer-bars"
    >
      <style>{`@keyframes cupertino-ui-eq { 0%,100% { height: 30% } 50% { height: 100% } }`}</style>
      {[0, 1, 2, 3].map((i) => (
        <span
          key={i}
          className="w-[3px] rounded-full bg-current"
          style={{
            height: "40%",
            animation: paused
              ? "none"
              : `cupertino-ui-eq ${0.7 + i * 0.13}s ease-in-out ${i * -0.19}s infinite`,
          }}
        />
      ))}
    </span>
  );
}

function TrackList({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="track-list"
      className={cn(
        "flex w-full flex-col [&>[data-slot=track-row]:not(:first-child)>[data-slot=track-row-inner]]:shadow-[0_-0.5px_0_0_var(--separator)]",
        className
      )}
      {...props}
    />
  );
}

function TrackRow({
  className,
  index,
  title,
  subtitle,
  artworkUrl,
  duration,
  active,
  playing,
  onMore,
  ...props
}: Omit<React.ComponentProps<"button">, "title"> & {
  /** 1-based track number (hidden while active). */
  index?: number;
  title: string;
  /** Artist line, for lists that mix albums. */
  subtitle?: string;
  /** Small artwork instead of a number (Songs list style). */
  artworkUrl?: string;
  /** Preformatted duration, e.g. "3:42". */
  duration?: string;
  /** This row is the current track. */
  active?: boolean;
  /** Whether audio is actually running (drives the bars). */
  playing?: boolean;
  /** Show the ellipsis button and call this when tapped. */
  onMore?: () => void;
}) {
  return (
    <button
      type="button"
      data-slot="track-row"
      className={cn(
        "group flex w-full cursor-default select-none items-center gap-3 pl-4 text-left outline-none focus-visible:bg-fill-quaternary active:bg-fill-tertiary",
        className
      )}
      {...props}
    >
      <span className="flex w-5 shrink-0 items-center justify-center">
        {active ? (
          <EqualizerBars paused={!playing} />
        ) : artworkUrl ? null : (
          <span className="text-subheadline tabular-nums text-secondary-label">
            {index}
          </span>
        )}
      </span>
      {artworkUrl ? (
        // eslint-disable-next-line @next/next/no-img-element
        <img
          src={artworkUrl}
          alt=""
          loading="lazy"
          className="-ml-2 size-11 shrink-0 rounded-[6px] object-cover shadow-[inset_0_0_0_0.5px_var(--separator)]"
        />
      ) : null}
      <span
        data-slot="track-row-inner"
        className="flex min-h-[44px] min-w-0 flex-1 items-center gap-3 py-2 pr-4"
      >
        <span className="flex min-w-0 flex-1 flex-col">
          <span className={cn("truncate text-body", active && "text-red")}>
            {title}
          </span>
          {subtitle ? (
            <span className="truncate text-footnote text-secondary-label">
              {subtitle}
            </span>
          ) : null}
        </span>
        {duration ? (
          <span className="shrink-0 text-footnote tabular-nums text-secondary-label">
            {duration}
          </span>
        ) : null}
        {onMore ? (
          <span
            role="button"
            tabIndex={-1}
            aria-label="More"
            onClick={(e) => {
              e.stopPropagation();
              onMore();
            }}
            className="flex size-7 shrink-0 items-center justify-center rounded-full text-secondary-label hover:bg-fill-quaternary"
          >
            <EllipsisIcon className="size-4" />
          </span>
        ) : null}
      </span>
    </button>
  );
}

export { EqualizerBars, TrackList, TrackRow };
